#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int *data;
    int size;
    int capacity;
} MaxHeap;

MaxHeap* createHeap(int cap) {
    MaxHeap *h = (MaxHeap*)malloc(sizeof(MaxHeap));
    h->data = (int*)malloc(sizeof(int) * cap);
    h->size = 0;
    h->capacity = cap;
    return h;
}

void swap(int *a, int *b) { int t=*a; *a=*b; *b=t; }

void heapifyUp(MaxHeap *h, int idx) {
    while (idx > 0) {
        int p = (idx - 1) / 2;
        if (h->data[idx] > h->data[p]) {
            swap(&h->data[idx], &h->data[p]);
            idx = p;
        } else break;
    }
}

void heapifyDown(MaxHeap *h, int idx) {
    while (1) {
        int l = 2*idx + 1, r = 2*idx + 2, largest = idx;
        if (l < h->size && h->data[l] > h->data[largest]) largest = l;
        if (r < h->size && h->data[r] > h->data[largest]) largest = r;
        if (largest != idx) {
            swap(&h->data[idx], &h->data[largest]);
            idx = largest;
        } else break;
    }
}

void push(MaxHeap *h, int val) {
    h->data[h->size++] = val;
    heapifyUp(h, h->size-1);
}

void pop(MaxHeap *h) {
    if (h->size == 0) return;
    h->data[0] = h->data[--h->size];
    heapifyDown(h, 0);
}

int top(MaxHeap *h) { return h->size ? h->data[0] : -1; }

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        MaxHeap *heap = createHeap(N);
        for (int i=0;i<N;i++) {
            char op; scanf(" %c", &op);
            if (op == '+') {
                int x; scanf("%d", &x);
                push(heap, x);
            } else {
                pop(heap);
            }
            printf("%d\n", top(heap));
        }
        free(heap->data);
        free(heap);
    }
    return 0;
}

