const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const T = parseInt(lines[idx++], 10);
let output = [];
for (let t = 0; t < T; ++t) {
  const N = parseInt(lines[idx++], 10);
  const heap = [];
  const push = (val) => {
    heap.push(-val);
    let i = heap.length - 1;
    while (i > 0) {
      const p = (i - 1) >> 1;
      if (heap[i] < heap[p]) {
        [heap[i], heap[p]] = [heap[p], heap[i]];
        i = p;
      } else break;
    }
  };
  const pop = () => {
    if (heap.length === 0) return;
    heap[0] = heap[heap.length - 1];
    heap.pop();
    let i = 0;
    while (true) {
      let l = i * 2 + 1, r = i * 2 + 2, smallest = i;
      if (l < heap.length && heap[l] < heap[smallest]) smallest = l;
      if (r < heap.length && heap[r] < heap[smallest]) smallest = r;
      if (smallest !== i) {
        [heap[i], heap[smallest]] = [heap[smallest], heap[i]];
        i = smallest;
      } else break;
    }
  };
  const top = () => -heap[0];
  for (let i = 0; i < N; ++i) {
    const parts = lines[idx++].trim().split(' ');
    if (parts[0] === '+') {
      push(parseInt(parts[1], 10));
    } else {
      pop();
    }
    output.push(String(top()));
  }
}
